import pandas as pd
import matplotlib.pyplot as plt
from datetime import datetime
import json

class WorkoutTracker:
    def __init__(self):
        self.workouts = pd.DataFrame(columns=['date', 'sport', 'duration', 'distance', 'calories', 'heart_rate', 'intensity_zone'])
        self.nutrition = pd.DataFrame(columns=['date', 'meal', 'calories', 'protein', 'carbs', 'fat'])

    def import_strava(self, strava_data):
        for entry in strava_data:
            self.workouts = self.workouts.append(entry, ignore_index=True)

    def import_polar_flow(self, polar_data):
        for entry in polar_data:
            self.workouts = self.workouts.append(entry, ignore_index=True)

    def import_myfitnesspal(self, mfp_data):
        for entry in mfp_data:
            self.nutrition = self.nutrition.append(entry, ignore_index=True)

    def aggregate_heart_rate(self):
        zones = {'rest': 0, 'light': 0, 'moderate': 0, 'hard': 0, 'max': 0}
        for index, row in self.workouts.iterrows():
            zone = self.determine_intensity_zone(row['heart_rate'])
            zones[zone] += row['duration']
        return zones

    def determine_intensity_zone(self, heart_rate):
        if heart_rate < 120:
            return 'rest'
        elif heart_rate < 140:
            return 'light'
        elif heart_rate < 160:
            return 'moderate'
        elif heart_rate < 180:
            return 'hard'
        else:
            return 'max'

    def plot_progress(self, metric='mileage'):
        if metric == 'mileage':
            self.workouts['date'] = pd.to_datetime(self.workouts['date'])
            self.workouts.set_index('date', inplace=True)
            self.workouts.resample('M')['distance'].sum().plot(title='Monthly Mileage Progress')
        elif metric == 'pace':
            self.workouts['pace'] = self.workouts['duration'] / self.workouts['distance']
            self.workouts['date'] = pd.to_datetime(self.workouts['date'])
            self.workouts.set_index('date', inplace=True)
            self.workouts.resample('M')['pace'].mean().plot(title='Monthly Pace Progress')
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.show()

    def customize_view(self, sport=None):
        if sport:
            return self.workouts[self.workouts['sport'] == sport]
        return self.workouts

# Example usage
tracker = WorkoutTracker()
strava_data = [
    {'date': '2023-01-01', 'sport': 'running', 'duration': 3600, 'distance': 10, 'calories': 600, 'heart_rate': 150, 'intensity_zone': 'moderate'},
    {'date': '2023-01-02', 'sport': 'cycling', 'duration': 7200, 'distance': 30, 'calories': 1200, 'heart_rate': 140, 'intensity_zone': 'light'}
]
polar_data = []
mfp_data = [{'date': '2023-01-01', 'meal': 'breakfast', 'calories': 400, 'protein': 20, 'carbs': 50, 'fat': 10}]

tracker.import_strava(strava_data)
tracker.import_polar_flow(polar_data)
tracker.import_myfitnesspal(mfp_data)

heart_rate_zones = tracker.aggregate_heart_rate()
print(heart_rate_zones)

