import pandas as pd
import matplotlib.pyplot as plt
from datetime import datetime
import json

class WorkoutTracker:
    def __init__(self):
        self.workouts = pd.DataFrame(columns=['date', 'sport', 'duration', 'distance', 'calories', 'heart_rate'])
        self.nutrition = pd.DataFrame(columns=['date', 'meal', 'calories', 'protein', 'carbs', 'fats'])

    def import_strava(self, strava_data):
        for entry in strava_data:
            self.workouts = self.workouts.append(entry, ignore_index=True)

    def import_polar(self, polar_data):
        for entry in polar_data:
            self.workouts = self.workouts.append(entry, ignore_index=True)

    def import_myfitnesspal(self, mfp_data):
        for entry in mfp_data:
            self.nutrition = self.nutrition.append(entry, ignore_index=True)

    def filter_workouts(self, sport=None):
        if sport:
            return self.workouts[self.workouts['sport'] == sport]
        return self.workouts

    def aggregate_heart_rate_zones(self):
        zones = {'low': 0, 'moderate': 0, 'high': 0}
        for index, row in self.workouts.iterrows():
            if row['heart_rate'] < 120:
                zones['low'] += row['duration']
            elif 120 <= row['heart_rate'] < 160:
                zones['moderate'] += row['duration']
            else:
                zones['high'] += row['duration']
        return zones

    def plot_progress(self, metric='mileage'):
        if metric == 'mileage':
            data = self.workouts.groupby('date')['distance'].sum()
        else:
            data = self.workouts.groupby('date')['duration'].sum()

        plt.figure(figsize=(10, 5))
        plt.plot(data.index, data.values, marker='o')
        plt.title(f'Progress by {metric.capitalize()}')
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.xticks(rotation=45)
        plt.tight_layout()
        plt.show()

    def save_data(self, filename):
        with open(filename, 'w') as f:
            json.dump({'workouts': self.workouts.to_dict(), 'nutrition': self.nutrition.to_dict()}, f)

    def load_data(self, filename):
        with open(filename, 'r') as f:
            data = json.load(f)
            self.workouts = pd.DataFrame.from_dict(data['workouts'])
            self.nutrition = pd.DataFrame.from_dict(data['nutrition'])

