import pandas as pd
import matplotlib.pyplot as plt
from datetime import datetime
import json

class WorkoutTracker:
    def __init__(self):
        self.workouts = pd.DataFrame(columns=['date', 'sport', 'duration', 'distance', 'calories', 'heart_rate', 'intensity_zone'])
        self.nutrition = pd.DataFrame(columns=['date', 'meal', 'calories', 'protein', 'carbs', 'fats'])

    def import_strava(self, strava_data):
        for entry in strava_data:
            self.workouts = self.workouts.append({
                'date': entry['date'],
                'sport': 'Running',
                'duration': entry['duration'],
                'distance': entry['distance'],
                'calories': entry['calories'],
                'heart_rate': entry['heart_rate'],
                'intensity_zone': self.calculate_intensity_zone(entry['heart_rate'])
            }, ignore_index=True)

    def import_polar(self, polar_data):
        for entry in polar_data:
            self.workouts = self.workouts.append({
                'date': entry['date'],
                'sport': entry['sport'],
                'duration': entry['duration'],
                'distance': entry['distance'],
                'calories': entry['calories'],
                'heart_rate': entry['heart_rate'],
                'intensity_zone': self.calculate_intensity_zone(entry['heart_rate'])
            }, ignore_index=True)

    def import_myfitnesspal(self, mfp_data):
        for entry in mfp_data:
            self.nutrition = self.nutrition.append({
                'date': entry['date'],
                'meal': entry['meal'],
                'calories': entry['calories'],
                'protein': entry['protein'],
                'carbs': entry['carbs'],
                'fats': entry['fats']
            }, ignore_index=True)

    def calculate_intensity_zone(self, heart_rate):
        if heart_rate < 120:
            return 'Zone 1'
        elif heart_rate < 140:
            return 'Zone 2'
        elif heart_rate < 160:
            return 'Zone 3'
        elif heart_rate < 180:
            return 'Zone 4'
        else:
            return 'Zone 5'

    def aggregate_heart_rate_zones(self):
        return self.workouts['intensity_zone'].value_counts()

    def plot_progress(self, metric='mileage'):
        if metric == 'mileage':
            data = self.workouts.groupby('date')['distance'].sum()
        else:
            data = self.workouts.groupby('date')['duration'].sum()

        plt.figure(figsize=(10, 5))
        plt.plot(data.index, data.values, marker='o')
        plt.title(f'Progress Over Time by {metric.capitalize()}')
        plt.xlabel('Date')
        plt.ylabel(metric.capitalize())
        plt.xticks(rotation=45)
        plt.tight_layout()
        plt.show()

    def customize_view(self, sport=None):
        if sport:
            return self.workouts[self.workouts['sport'] == sport]
        return self.workouts

