class RecipeApp:
    def __init__(self):
        self.recipes = {}
        self.ingredients = {}

    def add_recipe(self, name, ingredients):
        self.recipes[name] = ingredients

    def add_ingredient(self, name, quantity):
        self.ingredients[name] = quantity

    def view_recipes(self):
        return self.recipes

    def view_ingredients(self):
        return self.ingredients

    def search_recipes_by_ingredient(self, ingredient):
        return {name: ingredients for name, ingredients in self.recipes.items() if ingredient in ingredients}

    def total_ingredients(self):
        return sum(self.ingredients.values())

    def sort_recipes(self, by='name'):
        if by == 'name':
            return dict(sorted(self.recipes.items()))
        elif by == 'ingredients':
            return dict(sorted(self.recipes.items(), key=lambda item: len(item[1])))

    def display_recipe(self, name):
        return self.recipes.get(name, "Recipe not found.")

